1	//! Round-7 tests: the snapshot → compute → commit dispatch is concurrency-safe.
2	//!
3	//! These assert the concurrency CONTRACT probed live against the reference server
4	//! (`BEHAVIOR.md` §17, `QUERIES.log` [R71]–[R75]): with a long proof operation in
5	//! flight, unrelated and related requests are served concurrently, the fresh
6	//! version index is allocated at COMMIT (completion) — so an op that *starts* first
7	//! but *commits* last gets the HIGHER index — the not-yet-committed version is
8	//! invisible until it commits, and concurrent allocations never collide or skip.
9	//!
10	//! A `GatedProver` makes the slow op (`autoprove`) block on a controllable gate:
11	//! it signals when it has entered (its snapshot already taken, no lock held) and
12	//! then parks until the test releases it. This deterministically reproduces the
13	//! probed interleaving — slow-start → fast-commit → slow-commit — with no sleeps.
14	//! The fast op (`apply_method`) and every read never touch the gate.
15	
16	use std::sync::{Arc, Condvar, Mutex};
17	use std::thread;
18	
19	use web_clean::dispatch::{
20	    Content, MainReq, Meta, ProverOps, Request, RootMeta, Server,
21	};
22	use web_clean::page::Origin;
23	use web_clean::route::{Autoprove, AutoproveAll, AutoproveDiff, NavDir};
24	
25	// ---------------------------------------------------------------------------
26	// A controllable gate: the slow op enters (announcing it is mid-compute) and
27	// parks until the test releases it. One mutex guards both flags; the Condvar
28	// wait releases the mutex while parked, so the test can observe/act meanwhile.
29	// ---------------------------------------------------------------------------
30	
31	#[derive(Default)]
32	struct GateState {
33	    started: bool,
34	    released: bool,
35	}
36	
37	struct Gate {
38	    m: Mutex<GateState>,
39	    started_cv: Condvar,
40	    release_cv: Condvar,
41	}
42	
43	impl Gate {
44	    fn new() -> Gate {
45	        Gate { m: Mutex::new(GateState::default()), started_cv: Condvar::new(), release_cv: Condvar::new() }
46	    }
47	    /// Called by the slow op: announce entry, then park until released.
48	    fn enter_and_park(&self) {
49	        let mut g = self.m.lock().unwrap();
50	        g.started = true;
51	        self.started_cv.notify_all();
52	        while !g.released {
53	            g = self.release_cv.wait(g).unwrap();
54	        }
55	    }
56	    /// Called by the test: block until the slow op has entered its compute.
57	    fn wait_started(&self) {
58	        let mut g = self.m.lock().unwrap();
59	        while !g.started {
60	            g = self.started_cv.wait(g).unwrap();
61	        }
62	    }
63	    /// Called by the test: let the parked slow op proceed to commit.
64	    fn release(&self) {
65	        let mut g = self.m.lock().unwrap();
66	        g.released = true;
67	        self.release_cv.notify_all();
68	    }
69	}
