167	/// Extract the version index `N` from a `{"redirect":"/thy/trace/N/…"}` body.
168	fn redirect_index(body: &str) -> u64 {
169	    let marker = "/thy/trace/";
170	    let start = body.find(marker).expect("redirect body") + marker.len();
171	    let rest = &body[start..];
172	    let end = rest.find('/').unwrap_or(rest.len());
173	    rest[..end].parse().expect("numeric index")
174	}
