176	// ---------------------------------------------------------------------------
177	// The main interleaving test (BEHAVIOR §17.1–§17.4).
178	// ---------------------------------------------------------------------------
179	
180	#[test]
181	fn slow_op_in_flight_is_non_blocking_and_commits_last() {
182	    let gate = Arc::new(Gate::new());
183	    let server = Arc::new(Server::new(GatedProver { gate: gate.clone() }, base()));
184	
185	    // Launch the SLOW op (autoprove on idx1) on another thread. `dispatch(&self)`
186	    // lets the same server be shared; the op takes its snapshot, releases the state
187	    // lock, then parks inside `autoprove`.
188	    let slow_server = server.clone();
189	    let slow = thread::spawn(move || {
190	        slow_server
191	            .dispatch(&Request::get("/thy/trace/1/autoprove/idfs/0/False/proof/L"))
192	            .body
193	    });
194	
195	    // Wait until the slow op is provably mid-compute (snapshot taken, lock released).
196	    gate.wait_started();
197	
198	    // §17.1 NON-BLOCKING: an unrelated read is served immediately while the slow op
199	    // is parked — dispatch did not need exclusive ownership.
200	    let read = server.dispatch(&Request::get("/thy/trace/1/overview/help"));
201	    assert_eq!(read.status, 200, "a read must be served while a slow op is in flight");
202	
203	    // §17.2 A second (fast) proof op COMMITS while the slow op is still parked, so it
204	    // takes the LOWER index 2 — even though the slow op STARTED first.
205	    let fast = server.dispatch(&Request::get("/thy/trace/1/main/method/L/1"));
206	    assert_eq!(fast.status, 200);
207	    assert_eq!(redirect_index(&fast.body), 2, "fast op commits first -> lower index");
208	
209	    // §17.3 The slow op's version is NOT yet visible (allocation is at commit): only
210	    // 1 and 2 exist, and index 3 does not resolve yet.
211	    assert_eq!(server.versions(), vec![1, 2], "slow op's index must be invisible pre-commit");
212	    assert_eq!(
213	        server.dispatch(&Request::get("/thy/trace/3/overview/help")).status,
214	        404,
215	        "the not-yet-committed version must not resolve",
216	    );
217	
218	    // Release the slow op; it now commits AFTER the fast op and takes the HIGHER
219	    // index 3 (§17.2: completion order, independent of start order).
220	    gate.release();
221	    let slow_body = slow.join().unwrap();
222	    assert_eq!(redirect_index(&slow_body), 3, "slow op commits last -> higher index");
223	
224	    // §17.3/§17.4 Final set is contiguous with no collision or skip.
225	    assert_eq!(server.versions(), vec![1, 2, 3]);
226	    assert_eq!(server.dispatch(&Request::get("/thy/trace/3/overview/help")).status, 200);
227	}
