229	// ---------------------------------------------------------------------------
230	// Counter race: many simultaneous proof ops (BEHAVIOR §17.3/§17.4, [R74]).
231	// ---------------------------------------------------------------------------
232	
233	#[test]
234	fn concurrent_allocations_never_collide_or_skip() {
235	    // A gate that is pre-released so `autoprove` does not park: here every op is fast
236	    // and we stress the atomic allocation under a genuine thread race.
237	    let gate = Arc::new(Gate::new());
238	    gate.release();
239	    let server = Arc::new(Server::new(GatedProver { gate }, base()));
240	
241	    const N: u64 = 16;
242	    let mut handles = Vec::new();
243	    for _ in 0..N {
244	        let s = server.clone();
245	        handles.push(thread::spawn(move || {
246	            // A fast proof op (method) -> a fresh version each.
247	            redirect_index(&s.dispatch(&Request::get("/thy/trace/1/main/method/L/1")).body)
248	        }));
249	    }
250	    let mut got: Vec<u64> = handles.into_iter().map(|h| h.join().unwrap()).collect();
251	    got.sort_unstable();
252	
253	    // Exactly the contiguous block 2..=N+1: N distinct indices, no collision, no skip.
254	    let want: Vec<u64> = (2..=N + 1).collect();
255	    assert_eq!(got, want, "concurrent insert_new must be atomic, contiguous, unique");
256	    // The backend agrees: base + N new versions, all resolvable (retention).
257	    assert_eq!(server.versions(), (1..=N + 1).collect::<Vec<_>>());
258	}
